import { useState } from 'react';
import { motion } from 'framer-motion';
import { useGoogleAds } from '@/hooks/useGoogleAds';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Skeleton } from '@/components/ui/skeleton';
import { BarChart3, TrendingUp, MousePointer2, DollarSign, MapPin, AlertCircle } from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid } from 'recharts';

const item = {
    hidden: { y: 20, opacity: 0 },
    show: { y: 0, opacity: 1 }
};

export default function GoogleAdsPerformance() {
    const [viewMode, setViewMode] = useState<'all' | 'brand' | 'generic'>('all');
    const { campaigns, geoPerformance, keywords, isLoading } = useGoogleAds();

    if (isLoading) {
        return (
            <div className="space-y-6">
                <div className="flex justify-end"><Skeleton className="h-8 w-64 rounded-lg bg-white/5" /></div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                    {[1, 2, 3, 4].map(i => (
                        <Skeleton key={i} className="h-32 rounded-xl bg-white/5" />
                    ))}
                </div>
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    <Skeleton className="lg:col-span-2 h-[400px] rounded-3xl bg-white/5" />
                    <Skeleton className="h-[400px] rounded-3xl bg-white/5" />
                </div>
            </div>
        );
    }

    if (!campaigns?.length) {
        return (
            <div className="flex flex-col items-center justify-center p-12 text-center space-y-4 glass-card rounded-3xl border-white/5">
                <div className="p-4 bg-white/5 rounded-full">
                    <AlertCircle className="w-8 h-8 text-ch-text-dimmed" />
                </div>
                <div>
                    <h3 className="text-lg font-black text-ch-white uppercase">Aguardando Dados</h3>
                    <p className="text-sm text-ch-text-muted">Os dados estão sendo carregados ou não há campanhas ativas.</p>
                </div>
            </div>
        );
    }

    // Filter logic
    // Brand vs Generic keywords (mock logic)
    const brandKeywords = keywords?.filter(k => k.text.toLowerCase().includes('clickhero') || k.text.toLowerCase().includes('click hero')) || [];
    const genericKeywords = keywords?.filter(k => !k.text.toLowerCase().includes('clickhero') && !k.text.toLowerCase().includes('click hero')) || [];

    const activeKeywords = viewMode === 'brand' ? brandKeywords : viewMode === 'generic' ? genericKeywords : keywords;

    // Aggregate totals based on viewMode
    // Note: Since campaigns are high level, filtering them by keyword type is tricky without ad group association. 
    // For this UI demo, we will simulate the metrics shift based on the toggle.

    const modifier = viewMode === 'brand' ? 0.3 : viewMode === 'generic' ? 0.7 : 1;

    const totalImpressions = (campaigns?.reduce((acc, c) => acc + (c.impressions || 0), 0) || 0) * modifier;
    const totalClicks = (campaigns?.reduce((acc, c) => acc + (c.clicks || 0), 0) || 0) * modifier;
    const totalSpend = (campaigns?.reduce((acc, c) => acc + (c.spend || 0), 0) || 0) * modifier;
    const avgCtr = campaigns?.length ? (totalClicks / totalImpressions) * 100 : 0;

    // Mock chart generation
    const chartData = [
        { name: 'Seg', clicks: Math.floor(120 * modifier), impressions: Math.floor(4000 * modifier) },
        { name: 'Ter', clicks: Math.floor(180 * modifier), impressions: Math.floor(5500 * modifier) },
        { name: 'Qua', clicks: Math.floor(250 * modifier), impressions: Math.floor(8000 * modifier) },
        { name: 'Qui', clicks: Math.floor(190 * modifier), impressions: Math.floor(6200 * modifier) },
        { name: 'Sex', clicks: Math.floor(310 * modifier), impressions: Math.floor(9800 * modifier) },
        { name: 'Sab', clicks: Math.floor(150 * modifier), impressions: Math.floor(4500 * modifier) },
        { name: 'Dom', clicks: Math.floor(100 * modifier), impressions: Math.floor(3200 * modifier) },
    ];

    return (
        <div className="space-y-6">
            {/* Filter Toggle */}
            <div className="flex justify-end">
                <div className="bg-white/5 p-1 rounded-lg flex text-xs font-bold">
                    <button
                        onClick={() => setViewMode('all')}
                        className={`px-4 py-1.5 rounded-md transition-all ${viewMode === 'all' ? 'bg-ch-orange text-black' : 'text-ch-text-muted hover:text-ch-white'}`}
                    >
                        Visão Geral
                    </button>
                    <button
                        onClick={() => setViewMode('brand')}
                        className={`px-4 py-1.5 rounded-md transition-all ${viewMode === 'brand' ? 'bg-ch-orange text-black' : 'text-ch-text-muted hover:text-ch-white'}`}
                    >
                        Institucional (Brand)
                    </button>
                    <button
                        onClick={() => setViewMode('generic')}
                        className={`px-4 py-1.5 rounded-md transition-all ${viewMode === 'generic' ? 'bg-ch-orange text-black' : 'text-ch-text-muted hover:text-ch-white'}`}
                    >
                        Genérico (Topo de Funil)
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                <Card className="bg-white/[0.02] border-white/5">
                    <CardHeader className="flex flex-row items-center justify-between pb-2">
                        <CardTitle className="text-[10px] font-black uppercase tracking-widest text-ch-text-muted">Impressões</CardTitle>
                        <BarChart3 className="w-4 h-4 text-emerald-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-black text-ch-white">{Math.floor(totalImpressions).toLocaleString()}</div>
                        <p className="text-[10px] text-emerald-500 font-bold mt-1">Alcance da Marca</p>
                    </CardContent>
                </Card>
                <Card className="bg-white/[0.02] border-white/5">
                    <CardHeader className="flex flex-row items-center justify-between pb-2">
                        <CardTitle className="text-[10px] font-black uppercase tracking-widest text-ch-text-muted">Cliques</CardTitle>
                        <MousePointer2 className="w-4 h-4 text-[#4285F4]" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-black text-ch-white">{Math.floor(totalClicks).toLocaleString()}</div>
                        <p className="text-[10px] text-[#4285F4] font-bold mt-1">Tráfego Qualificado</p>
                    </CardContent>
                </Card>
                <Card className="bg-white/[0.02] border-white/5">
                    <CardHeader className="flex flex-row items-center justify-between pb-2">
                        <CardTitle className="text-[10px] font-black uppercase tracking-widest text-ch-text-muted">Investimento</CardTitle>
                        <DollarSign className="w-4 h-4 text-ch-orange" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-black text-ch-white">R$ {totalSpend.toLocaleString(undefined, { minimumFractionDigits: 2 })}</div>
                        <p className="text-[10px] text-ch-orange font-bold mt-1">ROI Controlado</p>
                    </CardContent>
                </Card>
                <Card className="bg-white/[0.02] border-white/5">
                    <CardHeader className="flex flex-row items-center justify-between pb-2">
                        <CardTitle className="text-[10px] font-black uppercase tracking-widest text-ch-text-muted">CTR Médio</CardTitle>
                        <TrendingUp className="w-4 h-4 text-purple-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-black text-ch-white">{avgCtr.toFixed(2)}%</div>
                        <p className="text-[10px] text-purple-500 font-bold mt-1">Relevância dos Anúncios</p>
                    </CardContent>
                </Card>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <motion.div variants={item} className="lg:col-span-2 glass-card rounded-3xl p-6 border-white/5">
                    <div className="flex items-center justify-between mb-6">
                        <h3 className="text-sm font-black text-ch-white uppercase tracking-tight">Evolução Diária</h3>
                    </div>
                    <div className="h-[300px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <AreaChart data={chartData}>
                                <defs>
                                    <linearGradient id="colorImpressions" x1="0" y1="0" x2="0" y2="1">
                                        <stop offset="5%" stopColor="#10b981" stopOpacity={0.3} />
                                        <stop offset="95%" stopColor="#10b981" stopOpacity={0} />
                                    </linearGradient>
                                    <linearGradient id="colorClicks" x1="0" y1="0" x2="0" y2="1">
                                        <stop offset="5%" stopColor="#4285F4" stopOpacity={0.3} />
                                        <stop offset="95%" stopColor="#4285F4" stopOpacity={0} />
                                    </linearGradient>
                                </defs>
                                <CartesianGrid strokeDasharray="3 3" stroke="#ffffff10" vertical={false} />
                                <XAxis dataKey="name" stroke="#ffffff40" fontSize={10} tickLine={false} axisLine={false} />
                                <YAxis stroke="#ffffff40" fontSize={10} tickLine={false} axisLine={false} tickFormatter={(value) => `${value}`} />
                                <Tooltip
                                    contentStyle={{ backgroundColor: '#111', borderColor: '#333', borderRadius: '8px' }}
                                    itemStyle={{ fontSize: '12px', fontWeight: 'bold' }}
                                    labelStyle={{ color: '#888', marginBottom: '4px' }}
                                />
                                <Area type="monotone" dataKey="impressions" stroke="#10b981" strokeWidth={2} fillOpacity={1} fill="url(#colorImpressions)" />
                                <Area type="monotone" dataKey="clicks" stroke="#4285F4" strokeWidth={2} fillOpacity={1} fill="url(#colorClicks)" />
                            </AreaChart>
                        </ResponsiveContainer>
                    </div>
                </motion.div>

                {/* Geo Performance Detailed Table */}
                <motion.div variants={item} className="glass-card rounded-3xl p-6 border-white/5 space-y-4">
                    <div className="flex items-center gap-3 mb-2">
                        <MapPin className="w-5 h-5 text-ch-orange" />
                        <div>
                            <h3 className="text-sm font-black text-ch-white uppercase tracking-tight">Performance por Unidade/Praça</h3>
                            <p className="text-[10px] text-ch-text-dimmed font-medium">Análise de canibalização e CPC</p>
                        </div>
                    </div>

                    <div className="space-y-1">
                        <div className="grid grid-cols-4 text-[9px] uppercase font-black text-ch-text-muted px-2 py-1">
                            <div className="col-span-2">Região/Cidade</div>
                            <div className="text-right">CPC</div>
                            <div className="text-right">CPM</div>
                        </div>
                        {geoPerformance?.slice(0, 8).map((geo, i) => {
                            const cpc = (geo.cost_micros / 1000000 / (geo.clicks || 1));
                            const cpm = (geo.cost_micros / 1000000 / (geo.impressions || 1)) * 1000;

                            return (
                                <div key={i} className="grid grid-cols-4 items-center p-2 rounded-lg hover:bg-white/5 transition-colors border-b border-white/5 last:border-0">
                                    <div className="col-span-2">
                                        <p className="text-[10px] font-bold text-ch-white">{geo.city_name || geo.region_name}</p>
                                        <p className="text-[8px] text-ch-text-dimmed">{geo.region_name}</p>
                                    </div>
                                    <div className="text-right">
                                        <p className={`text-[10px] font-bold ${cpc > 5 ? 'text-rose-500' : 'text-emerald-500'}`}>R$ {cpc.toFixed(2)}</p>
                                    </div>
                                    <div className="text-right">
                                        <p className="text-[10px] font-bold text-ch-text-muted">R$ {cpm.toFixed(2)}</p>
                                    </div>
                                </div>
                            );
                        })}
                    </div>

                    <Button variant="ghost" className="w-full text-[10px] font-black uppercase tracking-widest text-ch-text-muted hover:text-ch-white hover:bg-white/5 h-8 rounded-xl">
                        Ver todas as 50 unidades
                    </Button>
                </motion.div>
            </div>
        </div>
    );
}

import { Outlet, Navigate, useLocation } from 'react-router-dom';
import { Sidebar } from './Sidebar';
import { useAuth } from '@/contexts/AuthContext';
import { Loader2 } from 'lucide-react';
import AIChatPanel from '@/components/AIChatPanel';

interface AppLayoutProps {
    requireAuth?: boolean;
}

export function AppLayout({ requireAuth = true }: AppLayoutProps) {
    const { user, loading } = useAuth();

    // Show loading spinner while checking auth
    if (loading) {
        return (
            <div className="h-screen w-screen flex items-center justify-center bg-ch-black">
                <div className="flex flex-col items-center gap-3">
                    <Loader2 className="w-8 h-8 text-ch-orange animate-spin" />
                    <div className="flex flex-col items-center">
                        <span className="text-ch-white font-medium">Click.Hero</span>
                        <span className="text-ch-text-muted text-xs">Sincronizando seu ecossistema...</span>
                    </div>
                </div>
            </div>
        );
    }

    // Redirect to login if not authenticated and auth is required
    // Only redirect if loading is finished AND we explicitly have no user
    if (requireAuth && !user) {
        console.log('[AppLayout] No user found, redirecting to login');
        return <Navigate to="/login" replace />;
    }

    return (
        <div className="flex h-screen overflow-hidden bg-ch-black">
            <Sidebar />
            <main className="flex-1 overflow-y-auto">
                <div className="animate-fade-in">
                    <Outlet />
                </div>
            </main>
            <AIChatPanel />
        </div>
    );
}

// Auth layout for login/register pages
export function AuthLayout() {
    const { user, loading } = useAuth();

    // Show loading spinner while checking auth
    if (loading) {
        return (
            <div className="h-screen w-screen flex items-center justify-center bg-ch-black">
                <div className="flex flex-col items-center gap-3">
                    <Loader2 className="w-8 h-8 text-ch-orange animate-spin" />
                    <span className="text-ch-text-muted text-sm">Carregando...</span>
                </div>
            </div>
        );
    }

    const location = useLocation();
    const isLogin = location.pathname === '/login';

    if (user) {
        return <Navigate to="/dashboard" replace />;
    }

    if (isLogin) {
        return <Outlet />;
    }

    return (
        <div className="min-h-screen flex items-center justify-center bg-ch-black p-4">
            <div className="w-full max-w-md animate-fade-in">
                <Outlet />
            </div>
        </div>
    );
}

import { NavLink, useLocation } from 'react-router-dom';
import {
    LayoutDashboard,
    Megaphone,
    Palette,
    FileCheck,
    ClipboardList,
    Settings,
    Users,
    Building2,
    LogOut,
    ChevronLeft,
    ChevronRight,
    BarChart,
    Briefcase,
    CreditCard,
    Search
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { useAuth, useIsSuperAdmin, useIsCompanyAdmin } from '@/contexts/AuthContext';
import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import logo1 from '@/assets/login/logo-1.jpeg';

interface NavItem {
    icon: React.ElementType;
    label: string;
    href: string;
    roles?: Array<'super_admin' | 'company_admin' | 'operador'>;
}

const mainNavItems: NavItem[] = [
    { icon: LayoutDashboard, label: 'Dashboard', href: '/dashboard' },
    // { icon: Search, label: 'Google Ads', href: '/google-ads' },
    { icon: Megaphone, label: 'Campanhas', href: '/campanhas' },
    { icon: Palette, label: 'Criativos', href: '/criativos' },
    { icon: FileCheck, label: 'Auditorias', href: '/auditorias' },
    { icon: ClipboardList, label: 'Políticas', href: '/politicas' },
    { icon: BarChart, label: 'Relatórios', href: '/relatorios' },
    { icon: Briefcase, label: 'Marca', href: '/brand' },
];

const settingsNavItems: NavItem[] = [
    { icon: Settings, label: 'Integrações', href: '/integracoes', roles: ['super_admin', 'company_admin'] },
    { icon: Users, label: 'Usuários', href: '/usuarios', roles: ['super_admin', 'company_admin'] },
    { icon: Building2, label: 'Empresa', href: '/empresa', roles: ['super_admin', 'company_admin'] },
    { icon: CreditCard, label: 'Cobrança', href: '/billing', roles: ['super_admin', 'company_admin'] },
];

export function Sidebar() {
    const location = useLocation();
    const { user, signOut } = useAuth();
    const isSuperAdmin = useIsSuperAdmin();
    const isCompanyAdmin = useIsCompanyAdmin();
    const [collapsed, setCollapsed] = useState(false);

    const filterByRole = (items: NavItem[]) => {
        return items.filter(item => {
            if (!item.roles) return true;
            if (!user?.role) return false;
            return item.roles.includes(user.role);
        });
    };

    const isActive = (href: string) => location.pathname === href;

    return (
        <aside
            className={cn(
                'h-screen bg-[#0c0d0a]/80 backdrop-blur-xl border-r border-white/5 flex flex-col transition-all duration-500 ease-in-out relative',
                collapsed ? 'w-20' : 'w-64'
            )}
        >
            {/* Logo */}
            <div className="h-20 flex items-center px-5 border-b border-white/5 overflow-hidden">
                <motion.div
                    layout
                    className="flex items-center gap-3"
                >
                    <div className="w-10 h-10 bg-gradient-to-br from-ch-orange to-[#e07d04] rounded-xl flex items-center justify-center shadow-lg shadow-ch-orange/20 flex-shrink-0 overflow-hidden">
                        <img src={logo1} alt="ClickHero" className="w-full h-full object-cover" />
                    </div>
                    {!collapsed && (
                        <motion.div
                            initial={{ opacity: 0, x: -10 }}
                            animate={{ opacity: 1, x: 0 }}
                            className="flex flex-col"
                        >
                            <span className="font-bold text-lg leading-tight tracking-tight text-ch-white">
                                Click<span className="text-ch-orange">.</span>Hero
                            </span>
                            <span className="text-[10px] uppercase tracking-[0.2em] text-ch-text-dimmed font-medium">
                                Inteligência Publicitária
                            </span>
                        </motion.div>
                    )}
                </motion.div>
            </div>

            {/* Collapse Toggle */}
            <button
                onClick={() => setCollapsed(!collapsed)}
                className="absolute -right-3 top-24 w-7 h-7 bg-ch-dark-gray border border-white/10 rounded-full flex items-center justify-center hover:bg-ch-orange hover:border-ch-orange text-ch-text-muted hover:text-ch-black transition-all duration-300 z-50 shadow-xl"
            >
                {collapsed ? (
                    <ChevronRight className="w-4 h-4" />
                ) : (
                    <ChevronLeft className="w-4 h-4" />
                )}
            </button>

            {/* Main Navigation */}
            <nav className="flex-1 py-6 px-3 overflow-y-auto scrollbar-thin">
                <div className="space-y-1.5">
                    {mainNavItems.map((item, idx) => (
                        <motion.div
                            key={item.href}
                            initial={{ opacity: 0, x: -20 }}
                            animate={{ opacity: 1, x: 0 }}
                            transition={{ delay: idx * 0.05 }}
                        >
                            <NavLink
                                to={item.href}
                                className={cn(
                                    'flex items-center gap-3 px-3 py-3 rounded-xl text-sm font-medium transition-all duration-300 group relative',
                                    isActive(item.href)
                                        ? 'bg-ch-orange/10 text-ch-orange shadow-inner shadow-ch-orange/5'
                                        : 'text-ch-text-muted hover:bg-white/5 hover:text-ch-white'
                                )}
                            >
                                {isActive(item.href) && (
                                    <motion.div
                                        layoutId="active-pill"
                                        className="absolute left-0 w-1 h-6 bg-ch-orange rounded-r-full"
                                    />
                                )}
                                <item.icon className={cn(
                                    "w-5 h-5 flex-shrink-0 transition-transform duration-300",
                                    isActive(item.href) ? "scale-110" : "group-hover:scale-110"
                                )} />
                                {!collapsed && (
                                    <span className="truncate">{item.label}</span>
                                )}
                            </NavLink>
                        </motion.div>
                    ))}
                </div>

                {/* Settings Section */}
                {(isCompanyAdmin || isSuperAdmin) && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        transition={{ delay: 0.4 }}
                    >
                        <div className="mt-8 mb-3 px-4">
                            {!collapsed ? (
                                <span className="text-[10px] font-bold uppercase tracking-wide text-ch-text-dimmed/60">
                                    Configurações
                                </span>
                            ) : (
                                <span className="text-[10px] font-black uppercase tracking-wide text-ch-text-muted mb-4 px-2 block">
                                    Configurações
                                </span>
                            )}
                        </div>
                        <div className="space-y-1.5">
                            {filterByRole(settingsNavItems).map((item, idx) => (
                                <motion.div
                                    key={item.href}
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: 0.5 + idx * 0.05 }}
                                >
                                    <NavLink
                                        to={item.href}
                                        className={cn(
                                            'flex items-center gap-3 px-3 py-3 rounded-xl text-sm font-medium transition-all duration-300 group relative',
                                            isActive(item.href)
                                                ? 'bg-ch-orange/10 text-ch-orange shadow-inner shadow-ch-orange/5'
                                                : 'text-ch-text-muted hover:bg-white/5 hover:text-ch-white'
                                        )}
                                    >
                                        {isActive(item.href) && (
                                            <motion.div
                                                layoutId="active-pill-settings"
                                                className="absolute left-0 w-1 h-6 bg-ch-orange rounded-r-full"
                                            />
                                        )}
                                        <item.icon className={cn(
                                            "w-5 h-5 flex-shrink-0 transition-transform duration-300",
                                            isActive(item.href) ? "scale-110" : "group-hover:scale-110"
                                        )} />
                                        {!collapsed && (
                                            <span className="truncate">{item.label}</span>
                                        )}
                                    </NavLink>
                                </motion.div>
                            ))}
                        </div>
                    </motion.div>
                )}
            </nav>

            {/* User Section */}
            <div className="border-t border-white/5 p-4 bg-ch-black/20">
                {!collapsed ? (
                    <div className="flex items-center gap-2">
                        <NavLink
                            to="/settings"
                            className="flex items-center gap-3 flex-1 min-w-0 group cursor-pointer"
                        >
                            <div className="w-10 h-10 bg-gradient-to-br from-ch-dark-gray to-ch-black border border-white/5 group-hover:border-ch-orange/50 rounded-xl flex items-center justify-center text-ch-orange font-bold text-sm shadow-xl transition-all duration-300">
                                {user?.first_name?.[0]?.toUpperCase() || user?.email?.[0]?.toUpperCase() || 'U'}
                            </div>
                            <div className="flex-1 min-w-0">
                                <p className="text-sm font-bold text-ch-white truncate leading-tight group-hover:text-ch-orange transition-colors">
                                    {user?.first_name || 'Usuário'}
                                </p>
                                <p className="text-[10px] text-ch-text-dimmed truncate uppercase tracking-wider">
                                    {user?.company?.name || 'Sem empresa'}
                                </p>
                            </div>
                        </NavLink>
                        <button
                            onClick={signOut}
                            className="p-2.5 text-ch-text-dimmed hover:text-rose-500 hover:bg-white/5 rounded-xl transition-all duration-300"
                            title="Sair"
                        >
                            <LogOut className="w-4 h-4" />
                        </button>
                    </div>
                ) : (
                    <button
                        onClick={signOut}
                        className="w-full h-11 text-ch-text-dimmed hover:text-ch-orange hover:bg-white/5 rounded-xl transition-all duration-300 flex items-center justify-center shadow-inner"
                        title="Sair"
                    >
                        <LogOut className="w-5 h-5" />
                    </button>
                )}
            </div>
        </aside >
    );
}
